create extension if not exists "pgcrypto";
create table if not exists public.personal_info (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, nome text default '', cognome text default '', data_nascita date, citta_residenza text default '', nazione text default '', telefono text default '', email_cv text default '', job_title text default '', summary text default '', photo_url text default '', public_slug text unique not null, is_public boolean not null default true, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(user_id));
create table if not exists public.work_experiences (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, role_title text not null, company text default '', start_date date, end_date date, description text default '', is_hidden boolean not null default false, created_at timestamptz not null default now());
create table if not exists public.educations (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, title text not null, institution text default '', field_of_study text default '', start_date date, end_date date, location text default '', grade text default '', description text default '', is_hidden boolean not null default false, created_at timestamptz not null default now());
create table if not exists public.languages (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, lingua text not null, livello text not null default 'basic', acquired_date date, is_hidden boolean not null default false, created_at timestamptz not null default now());
create table if not exists public.skills (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, name text not null, acquired_date date, description text default '', is_hidden boolean not null default false, created_at timestamptz not null default now());
create table if not exists public.awards (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, title text not null, issuer text default '', date date, description text default '', is_hidden boolean not null default false, created_at timestamptz not null default now());
create table if not exists public.projects (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, title text not null, role text default '', description text default '', start_date date, end_date date, is_hidden boolean not null default false, created_at timestamptz not null default now());
create table if not exists public.case_studies (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, title text not null, context text default '', solution text default '', impact text default '', date date, is_hidden boolean not null default false, created_at timestamptz not null default now());
create or replace function public.set_updated_at() returns trigger as $$ begin new.updated_at = now(); return new; end; $$ language plpgsql;
drop trigger if exists personal_info_updated_at on public.personal_info;
create trigger personal_info_updated_at before update on public.personal_info for each row execute function public.set_updated_at();
alter table public.personal_info enable row level security; alter table public.work_experiences enable row level security; alter table public.educations enable row level security; alter table public.languages enable row level security; alter table public.skills enable row level security; alter table public.awards enable row level security; alter table public.projects enable row level security; alter table public.case_studies enable row level security;
do $$ declare r record; begin for r in select schemaname,tablename,policyname from pg_policies where schemaname='public' loop execute format('drop policy if exists %I on %I.%I', r.policyname, r.schemaname, r.tablename); end loop; end $$;
create policy "personal owner select" on public.personal_info for select using (auth.uid()=user_id); create policy "personal public select" on public.personal_info for select using (is_public=true); create policy "personal owner insert" on public.personal_info for insert with check (auth.uid()=user_id); create policy "personal owner update" on public.personal_info for update using (auth.uid()=user_id) with check (auth.uid()=user_id); create policy "personal owner delete" on public.personal_info for delete using (auth.uid()=user_id);
create policy "work owner all" on public.work_experiences for all using (auth.uid()=user_id) with check (auth.uid()=user_id); create policy "education owner all" on public.educations for all using (auth.uid()=user_id) with check (auth.uid()=user_id); create policy "languages owner all" on public.languages for all using (auth.uid()=user_id) with check (auth.uid()=user_id); create policy "skills owner all" on public.skills for all using (auth.uid()=user_id) with check (auth.uid()=user_id); create policy "awards owner all" on public.awards for all using (auth.uid()=user_id) with check (auth.uid()=user_id); create policy "projects owner all" on public.projects for all using (auth.uid()=user_id) with check (auth.uid()=user_id); create policy "case studies owner all" on public.case_studies for all using (auth.uid()=user_id) with check (auth.uid()=user_id);
create policy "work public select" on public.work_experiences for select using (is_hidden=false and exists(select 1 from public.personal_info p where p.user_id=work_experiences.user_id and p.is_public=true)); create policy "education public select" on public.educations for select using (is_hidden=false and exists(select 1 from public.personal_info p where p.user_id=educations.user_id and p.is_public=true)); create policy "languages public select" on public.languages for select using (is_hidden=false and exists(select 1 from public.personal_info p where p.user_id=languages.user_id and p.is_public=true)); create policy "skills public select" on public.skills for select using (is_hidden=false and exists(select 1 from public.personal_info p where p.user_id=skills.user_id and p.is_public=true)); create policy "awards public select" on public.awards for select using (is_hidden=false and exists(select 1 from public.personal_info p where p.user_id=awards.user_id and p.is_public=true)); create policy "projects public select" on public.projects for select using (is_hidden=false and exists(select 1 from public.personal_info p where p.user_id=projects.user_id and p.is_public=true)); create policy "case studies public select" on public.case_studies for select using (is_hidden=false and exists(select 1 from public.personal_info p where p.user_id=case_studies.user_id and p.is_public=true));
